        elif unavailable and settings.hibp_fail_closed:
            add_error(errors, "password", "breach_check_unavailable", "Password breach check is temporarily unavailable.")

    if errors:
        return JSONResponse(
            status_code=422,
            content={
                "ok": False,
                "error": {
                    "code": "validation_failed",
                    "message": "One or more fields are invalid.",
                    "details": errors,
                },
            },
        )

    for key in (
        f"email:{hash_identifier(email_info['canonical'])}",
        f"username:{hash_identifier(username)}",
    ):
        allowed, retry_after = rate_limiter.hit(
            key,
            settings.rate_identifier_limit,
            settings.rate_identifier_window,
        )
        if not allowed:
            return rate_limit_response(retry_after)

    password_hash = await asyncio.to_thread(ARGON2.hash, password)

    user = User(
        email=email_info["email"],
        email_canonical=email_info["canonical"],
        username=username,
        username_canonical=username,
        display_name=display_name,
        password_hash=password_hash,
        email_verified=False,
    )

    try:
        db.add(user)
        db.commit()
    except IntegrityError as exc:
        db.rollback()
        conflict = integrity_conflict_field(exc)

        if conflict == "email":
            # Account enumeration protection: duplicate email gets same response as accepted registration.
            return accepted_response()

        if conflict == "username":
            return JSONResponse(
                status_code=409,
                content={
                    "ok": False,
                    "error": {
                        "code": "registration_conflict",
                        "message": "Registration could not be completed with these identifiers.",
                        "details": [
                            {
                                "field": "username",
                                "code": "unavailable",
                                "message": "Choose a different username.",
                            }
                        ],
                    },
                },
            )

        return JSONResponse(
            status_code=409,
            content={
                "ok": False,
                "error": {
                    "code": "registration_conflict",
                    "message": "Registration could not be completed.",
                },
            },
        )

    # In production, enqueue a verification email here.
    return accepted_response()
